const gs = flow.get("tracking_points");

var m = { overlay: "Tracking points", geojson: gs, fit: true };

msg.payload = { command: { map: m, lat: 39.56369678374537, lon: -0.3115750026142905, layer: "points" } };

return msg;

const geojson = flow.get("tracking_points");
let index = parseInt(flow.get("tracking_index"));
if (index == geojson["features"].length){
    index =0;
}
const coords = geojson["features"][index]["geometry"]["coordinates"];
msg.payload = {lat: coords[1], lon: coords[0]};
flow.set("tracking_index",++index);
return msg;

const event = JSON.parse(msg.payload);

var thing = {
    name:"Pepe", 
    lat:event['lat'], 
    lon:event['lon'],
    icon:"car",
    iconColor:"darkred",
    zone: event['zone'],
    layer: "xcar"
};
msg.payload = thing;
return msg;
